import bisect

class Inventory:
    def __init__(self):
        self.inventory = []

    def insert(self, sku, name, price):
        if not isinstance(sku, str) or len(sku) == 0:
            raise ValueError("Invalid SKU format. It should be a non-empty string.")
        if sku in self.inventory:
            raise ValueError("Duplicate SKU found.")
        self.inventory.append((sku, name, price))
        self.inventory.sort()

    def delete(self, sku):
        if not isinstance(sku, str) or len(sku) == 0:
            raise ValueError("Invalid SKU format. It should be a non-empty string.")
        try:
            index = self.inventory.index((sku, None, None))
            del self.inventory[index]
        except ValueError:
            raise ValueError("Inventory entry not found.")

    def search(self, sku):
        if not isinstance(sku, str) or len(sku) == 0:
            raise ValueError("Invalid SKU format. It should be a non-empty string.")
        index = bisect.bisect_left(self.inventory, (sku, None, None))
        if index != len(self.inventory) and self.inventory[index][0] == sku:
            return self.inventory[index][1]
        return None

    def update(self, sku, name=None, price=None):
        if not isinstance(sku, str) or len(sku) == 0:
            raise ValueError("Invalid SKU format. It should be a non-empty string.")
        for i, (s, n, p) in enumerate(self.inventory):
            if s == sku:
                if name is not None:
                    self.inventory[i] = (sku, name, None)
                if price is not None:
                    self.inventory[i] = (sku, None, price)
                self.inventory.sort()
                return
        raise ValueError("Inventory entry not found.")

    def display(self):
        for sku, name, price in self.inventory:
            print(f"SKU: {sku}, Name: {name}, Price: {price}")


