#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Define the structure for a queue
typedef struct Queue {
    int* seats;
    int front;
    int rear;
    int size;
} Queue;

// Function to initialize the queue
void initQueue(Queue* queue) {
    queue->seats = (int*)malloc(100 * sizeof(int));
    queue->front = 0;
    queue->rear = 0;
    queue->size = 0;
}

// Function to check if the queue is empty
int isEmpty(Queue* queue) {
    return queue->size == 0;
}

// Function to check if the queue is full
int isFull(Queue* queue) {
    return queue->size == 100;
}

// Function to add an element to the queue
void enqueue(Queue* queue, int seat) {
    if (isFull(queue)) {
        printf("Queue is full. Cannot add more seats.\n");
        return;
    }
    queue->seats[queue->rear] = seat;
    queue->rear = (queue->rear + 1) % 100;
    queue->size++;
}

// Function to remove an element from the queue
int dequeue(Queue* queue) {
    if (isEmpty(queue)) {
        printf("Queue is empty. Cannot remove seats.\n");
        return -1;
    }
    int seat = queue->seats[queue->front];
    queue->seats[queue->front] = -1; // Mark as unavailable
    queue->front = (queue->front + 1) % 100;
    queue->size--;
    return seat;
}

// Function to book a ticket
int bookTicket(Queue* queue, int seatNumber) {
    int seat = dequeue(queue);
    if (seat != -1) {
        printf("Ticket booked for seat %d.\n", seatNumber);
        enqueue(queue, seat);
    } else {
        printf("Seat %d is not available.\n", seatNumber);
    }
    return seat;
}

// Function to cancel a ticket
int cancelTicket(Queue* queue, int seatNumber) {
    int seat = dequeue(queue);
    if (seat != -1) {
        printf("Ticket cancelled for seat %d.\n", seatNumber);
        enqueue(queue, seat);
    } else {
        printf("Seat %d is already cancelled or not booked.\n", seatNumber);
    }
    return seat;
}

int main() {
    Queue queue;
    initQueue(&queue);

    // Book 5 tickets
    bookTicket(&queue, 1);
    bookTicket(&queue, 2);
    bookTicket(&queue, 3);
    bookTicket(&queue, 4);
    bookTicket(&queue, 5);

    // Cancel a ticket
    cancelTicket(&queue, 2);

    // Book another ticket
    bookTicket(&queue, 6);

    return 0;
}
