// Define a custom error type for invalid input cases
#[derive(Debug)]
pub enum Error {
    EmptyArray,
    UnsupportedType,
}

// Implement the Display trait for the custom error type
impl fmt::Display for Error {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            Error::EmptyArray => write!(f, "Cannot shuffle an empty array"),
            Error::UnsupportedType => write!(f, "Unsupported data type"),
        }
    }
}

// Define a function to shuffle an array
pub fn shuffle<T: Clone + Copy>(arr: &mut [T]) -> Result<(), Error> {
    if arr.len() == 0 {
        return Err(Error::EmptyArray);
    }

    for i in 1..arr.len() {
        let j = rand::thread_rng().gen_range(0..i + 1);
        arr.swap(i, j);
    }

    Ok(())
}

// Example usage:
fn main() -> Result<(), Error> {
    let mut arr = [1, 2, 3, 4, 5, 6, 7, 8, 9];
    shuffle(&mut arr)?;

    println!("{:?}", arr);

    Ok(())
}
