using namespace std;

struct LogEntry {
    string timestamp;
    string event;
};

class LogDatabase {
private:
    vector<LogEntry> sortedLogs;
    unordered_map<string, int> timestampMap;

public:
    void addLog(LogEntry log) {
        if (timestampMap.find(log.timestamp) != timestampMap.end()) {
            timestampMap[log.timestamp]++;
        } else {
            timestampMap[log.timestamp] = 1;
        }
    }

    void updateLog(LogEntry log) {
        if (timestampMap.find(log.timestamp) != timestampMap.end()) {
            timestampMap[log.timestamp]++;
        }
    }

    void deleteLog(LogEntry log) {
        if (timestampMap.find(log.timestamp) != timestampMap.end()) {
            timestampMap[log.timestamp]--;
        }
    }

    void printLogs() {
        for (auto& entry : sortedLogs) {
            cout << entry.timestamp << ": " << entry.event << endl;
        }
    }

    vector<LogEntry> queryLogs(string startTimestamp, string endTimestamp) {
        auto startIt = lower_bound(sortedLogs.begin(), sortedLogs.end(), LogEntry(startTimestamp, ""), [](const LogEntry& a, const LogEntry& b) {
            return a.timestamp < b.timestamp;
        });
        auto endIt = upper_bound(sortedLogs.begin(), sortedLogs.end(), LogEntry(endTimestamp, ""), [](const LogEntry& a, const LogEntry& b) {
            return a.timestamp < b.timestamp;
        });

        vector<LogEntry> result;
        for (auto it = startIt; it != endIt; ++it) {
            if (it->timestamp == startTimestamp) {
                result.push_back(*it);
                sortedLogs.erase(it);
                it = lower_bound(sortedLogs.begin(), sortedLogs.end(), LogEntry(startTimestamp, ""), [](const LogEntry& a, const LogEntry& b) {
                    return a.timestamp < b.timestamp;
                });
            }
            if (it->timestamp == endTimestamp) {
                result.push_back(*it);
                sortedLogs.erase(it);
                it = upper_bound(sortedLogs.begin(), sortedLogs.end(), LogEntry(endTimestamp, ""), [](const LogEntry& a, const LogEntry& b) {
                    return a.timestamp < b.timestamp;
                });
            }
            result.push_back(*it);
        }
        return result;
    }
};

int main() {
    LogDatabase db;

    LogEntry log1 = {"2022-01-01 12:00:00", "Event 1"};
    LogEntry log2 = {"2022-01-01 13:00:00", "Event 2"};
    LogEntry log3 = {"2022-01-01 12:00:00", "Event 1"};
    LogEntry log4 = {"2022-01-02 12:00:00", "Event 1"};

    db.addLog(log1);
    db.addLog(log2);
    db.addLog(log3);
    db.addLog(log4);

    db.printLogs();

    vector<LogEntry> result = db.queryLogs("2022-01-01 12:00:00", "2022-01-01 13:00:00");
    cout << "Query results:" << endl;
    for (auto& entry : result) {
        cout << entry.timestamp << ": " << entry.event << endl;
    }

