import java.util.*;

class Node {
    int id;
    Node parent;

    public Node(int id) {
        this.id = id;
        this.parent = null;
    }
}

class BinaryLifting {
    private Map<Integer, Node> nodes;
    private Map<Integer, Integer> parentMap;

    public BinaryLifting() {
        this.nodes = new HashMap<>();
        this.parentMap = new HashMap<>();
    }

    public void addNode(int id, int parentId) {
        Node node = new Node(id);
        nodes.put(id, node);
        if (parentId != -1) {
            Node parent = nodes.get(parentId);
            node.parent = parent;
            parentMap.put(id, parentId);
        }
    }

    public int findLCA(int id1, int id2) {
        return findLCAHelper(id1, id2, nodes.get(id1), nodes.get(id2));
    }

    private int findLCAHelper(int id1, int id2, Node node1, Node node2) {
        if (node1.id == node2.id) {
            return node1.id;
        }

        if (node1.parent == null) {
            return node2.id;
        }

        if (node2.parent == null) {
            return node1.id;
        }

        int parent1 = parentMap.get(node1.id);
        int parent2 = parentMap.get(node2.id);

        if (parent1 == parent2) {
            return parent1;
        }

        int lca = findLCAHelper(parent1, parent2, node1.parent, node2.parent);
        return lca;
    }

    public static void main(String[] args) {
        BinaryLifting bl = new BinaryLifting();
        bl.addNode(1, -1);
        bl.addNode(2, 1);
        bl.addNode(3, 1);
        bl.addNode(4, 2);
        bl.addNode(5, 2);
        bl.addNode(6, 3);

        System.out.println("Lowest Common Ancestor of 2 and 4: " + bl.findLCA(2, 4));
        System.out.println("Lowest Common Ancestor of 3 and 5: " + bl.findLCA(3, 5));
    }
}
