using namespace std;

// Structure to represent a document
struct Document {
    string id;
    map<string, vector<int>> index;
};

// Function to load a document from a file
Document loadDocument(const string& filePath) {
    Document doc;
    ifstream file(filePath);
    if (file.is_open()) {
        string line, word;
        getline(file, line);
        doc.id = line;
        stringstream ss(line);
        while (getline(ss, word, ' ')) {
            doc.index[word].push_back(doc.id.size());
        }
        file.close();
    }
    return doc;
}

// Function to construct the inverted index
map<string, vector<string>> constructIndex(const vector<Document>& docs) {
    map<string, vector<string>> index;
    for (const auto& doc : docs) {
        for (const auto& pair : doc.index) {
            const string& word = pair.first;
            const vector<int>& indices = pair.second;
            for (int index : indices) {
                index.push_back(word);
            }
        }
    }
    return index;
}

// Function to search for keywords in the inverted index
vector<string> search(const map<string, vector<string>>& index, const vector<string>& keywords) {
    vector<string> results;
    for (const auto& pair : index) {
        const string& word = pair.first;
        const vector<string>& indices = pair.second;
        if (find(keywords.begin(), keywords.end(), word) != keywords.end()) {
            results.push_back(word);
        }
    }
    return results;
}

int main() {
    // Load documents from various formats
    vector<Document> docs;
    docs.push_back(loadDocument("document1.txt"));
    docs.push_back(loadDocument("document2.txt"));
    docs.push_back(loadDocument("document3.txt"));

    // Construct the inverted index
    map<string, vector<string>> index = constructIndex(docs);

    // Search for keywords in the inverted index
    vector<string> keywords = {"keyword1", "keyword2"};
    vector<string> results = search(index, keywords);

    // Print the results
    cout << "Search results: ";
    for (const string& result : results) {
        cout << result << " ";
    }
    cout << endl;

    return 0;
}
