use std::fs::File;
use std::io::{BufRead, BufReader};
use std::str::FromStr;

fn miller_rabin(n: u64, k: u32) -> bool {
    if n == 2 || n == 3 {
        return true;
    }

    if n <= 1 || n % 2 == 0 {
        return false;
    }

    let mut r = 0;
    let mut s = n - 1;

    while s % 2 == 0 {
        r += 1;
        s /= 2;
    }

    for _ in 0..k {
        let mut a = rand::thread_rng().gen_range(2, n - 1);
        let mut x = pow_mod(a, s, n);
        if x != 1 && x != n - 1 {
            let mut y = pow_mod(x, 2, n);
            if y == n - 1 {
                continue;
            }
            while y != n - 1 && y != 1 {
                x = pow_mod(x, 2, n);
                if x == 1 {
                    return false;
                }
                y = pow_mod(y, 2, n);
            }
            if y != n - 1 {
                return false;
            }
        }
    }
    true
}

fn pow_mod(mut x: u64, mut y: u64, mod: u64) -> u64 {
    let mut res = 1;
    while y > 0 {
        if y % 2 == 1 {
            res = (res * x) % mod;
        }
        x = (x * x) % mod;
        y /= 2;
    }
    res
}

fn main() {
    let file = File::open("input.txt").unwrap();
    let reader = BufReader::new(file);

    let mut numbers = Vec::new();

    for line in reader.lines() {
        let line = line.unwrap();
        let num: u64 = FromStr::from_str(&line).unwrap();
        numbers.push(num);
    }

    for num in numbers {
        if !miller_rabin(num, 5) {
            println!("{} is not a prime number", num);
        } else {
            println!("{} is a prime number", num);
        }
    }
}
