import java.io.*;
import java.util.*;

public class DynamicInventorySystem {
    private static final String FILE_NAME = "inventory.dat";
    private static final String SEPARATOR = ",";
    private static final String ID_SEPARATOR = "|";

    private Map<String, Item> inventory;
    private Set<String> fileIds;

    public DynamicInventorySystem() {
        inventory = new HashMap<>();
        fileIds = new HashSet<>();
    }

    public void add(String id, String name, double quantity) {
        String itemId = id + ID_SEPARATOR + name;
        inventory.put(itemId, new Item(id, name, quantity));
        fileIds.add(id);
    }

    public void remove(String id) {
        String itemId = id + ID_SEPARATOR + inventory.get(itemId).getName();
        inventory.remove(itemId);
        fileIds.remove(id);
    }

    public Item find(String id) {
        String itemId = id + ID_SEPARATOR + inventory.get(itemId).getName();
        return inventory.get(itemId);
    }

    public void saveToFile() {
        try (BufferedWriter writer = new BufferedWriter(new FileWriter(FILE_NAME))) {
            for (Map.Entry<String, Item> entry : inventory.entrySet()) {
                writer.write(entry.getKey() + SEPARATOR);
                writer.write(entry.getValue().getId() + SEPARATOR + entry.getValue().getName() + SEPARATOR + entry.getValue().getQuantity());
                writer.newLine();
            }
        } catch (IOException e) {
            System.err.println("Error saving to file: " + e.getMessage());
        }
    }

    public void loadFromFile() {
        try (BufferedReader reader = new BufferedReader(new FileReader(FILE_NAME))) {
            String line;
            while ((line = reader.readLine()) != null) {
                String[] parts = line.split(SEPARATOR);
                String itemId = parts[0] + ID_SEPARATOR + parts[1];
                String[] idAndName = itemId.split(ID_SEPARATOR);
                String id = idAndName[0];
                String name = idAndName[1];
                double quantity = Double.parseDouble(parts[2]);
                inventory.put(itemId, new Item(id, name, quantity));
                fileIds.add(id);
            }
        } catch (IOException e) {
            System.err.println("Error loading from file: " + e.getMessage());
        }
    }

    public static class Item {
        private String id;
        private String name;
        private double quantity;

        public Item(String id, String name, double quantity) {
            this.id = id;
            this.name = name;
            this.quantity = quantity;
        }

        public String getId() {
            return id;
        }

        public String getName() {
            return name;
        }

        public double getQuantity() {
            return quantity;
        }
    }

    public static void main(String[] args) {
        DynamicInventorySystem inventorySystem = new DynamicInventorySystem();
        inventorySystem.add("1", "Product A", 100);
        inventorySystem.add("2", "Product B", 50);
        inventorySystem.saveToFile();
        System.out.println(inventorySystem.find("1").getName());
        inventorySystem.remove("1");
        inventorySystem.loadFromFile();
        System.out.println(inventorySystem.find("2").getQuantity());
    }
}
