#include <iostream>
#include <vector>
#include <string>
#include <unordered_map>
#include <unordered_set>

using namespace std;

class Node {
public:
    unordered_map<char, Node*> children;
    bool isEndOfWord;

    Node() : isEndOfWord(false) {}
};

class SuffixTree {
private:
    Node* root;
    unordered_map<string, vector<int>> occurrences;

public:
    SuffixTree(string text) {
        root = new Node();
        int n = text.size();

        for (int i = 0; i < n; ++i) {
            Node* node = root;
            for (int j = i; j < n; ++j) {
                if (node->children.find(text[j]) == node->children.end()) {
                    node->children[text[j]] = new Node();
                }
                node = node->children[text[j]];
            }
            node->isEndOfWord = true;
            occurrences[text.substr(i)].push_back(node->isEndOfWord);
        }
    }

    vector<int> findSubstring(string substring) {
        if (substring.empty()) {
            throw invalid_argument("Substring cannot be empty");
        }

        Node* node = root;
        for (char c : substring) {
            if (node->children.find(c) == node->children.end()) {
                throw invalid_argument("Substring not found in the text");
            }
            node = node->children[c];
        }

        vector<int> indices;
        if (node->isEndOfWord) {
            indices.push_back(0);
        }

        for (int i = 0; i < substring.size(); ++i) {
            if (node->children.find(substring[i]) != node->children.end()) {
                node = node->children[substring[i]];
                if (node->isEndOfWord) {
                    indices.push_back(i + 1);
                }
            } else {
                break;
            }
        }

        return indices;
    }

    void printTree(string prefix, Node* node, int depth = 0) {
        if (node->isEndOfWord) {
            cout << prefix << " (End of word)" << endl;
        } else {
            cout << prefix << endl;
        }

        for (auto& child : node->children) {
            printTree(prefix + child.first, child.second, depth + 1);
        }
    }
};

int main() {
    string text = "banana";
    string substring = "ana";

    SuffixTree tree(text);
    vector<int> indices = tree.findSubstring(substring);

    cout << "Substring '" << substring << "' found at indices: ";
    for (int index : indices) {
        cout << index << " ";
    }
    cout << endl;

    return 0;
}
