// Structure to hold median data
typedef struct {
    int count;
    double* medians;
} MedianData;

// Median calculation function
double calculate_median(double* data, int size) {
    if (size == 0) return 0.0;
    qsort(data, size, sizeof(data[0]), compare);
    int mid = size / 2;
    if (size % 2 == 0) return (data[mid - 1] + data[mid]) / 2;
    return data[mid];
}

// Comparison function for sorting
int compare(const void* a, const void* b) {
    SensorData* sdata1 = (SensorData*)a;
    SensorData* sdata2 = (SensorData*)b;
    return sdata1->sensor_id - sdata2->sensor_id;
}

// Sensor connection callback function
void* sensor_callback(void* arg) {
    SensorData* data = (SensorData*)arg;
    while (1) {
        // Read data from sensor
        double temperature;
        // Simulate sensor reading
        temperature = (double)rand() / RAND_MAX;
        data->temperature = temperature;
        printf("Sensor %d: Temperature = %.2f\n", data->sensor_id, temperature);

        // Log error if temperature reading fails
        if (temperature < 0 || temperature > 100) {
            syslog(LOG_ERR, "Invalid temperature reading from sensor %d", data->sensor_id);
        }

        // Update median
        MedianData* medians = (MedianData*)data->medians;
        medians->count++;
        medians->medians[medians->count - 1] = temperature;
        double median = calculate_median(medians->medians, medians->count);
        printf("Median Temperature = %.2f\n", median);

        // Sleep for 1 second
        sleep(1);
    }
    return NULL;
}

// Add sensor function
void add_sensor(SensorData* data, MedianData* medians, int sensor_id) {
    data->sensor_id = sensor_id;
    data->medians = (double*)malloc(sizeof(double) * 10);
    medians->count = 0;
    medians->medians[medians->count] = data->temperature;
}

int main() {
    // Initialize logger
    openlog("Sensor Program", LOG_PID, LOG_USER);

    // Create sensor data and median data structures
    SensorData* sensors[10];
    MedianData* medians;
    medians = (MedianData*)malloc(sizeof(MedianData));
    medians->count = 0;
    medians->medians = (double*)malloc(sizeof(double) * 10);

    // Create semaphores for sensor connections
    sem_t* semaphores = (sem_t*)malloc(sizeof(sem_t) * 10);
    for (int i = 0; i < 10; i++) {
        semaphores[i] = sem_open("/sensor_connection_" + itoa(i, NULL, 10), O_CREAT, 0644, 1);
    }

    // Create threads for sensor connections
    pthread_t threads[10];
    for (int i = 0; i < 10; i++) {
        sem_t* semaphore = &semaphores[i];
        SensorData data;
        add_sensor(&data, medians, i);
        pthread_create(&threads[i], NULL, sensor_callback, &data);
        pthread_detach(threads[i]);
    }

    // Wait for all sensor threads to finish
    for (int i = 0; i < 10; i++) {
        sem_close(semaphores + i);
        sem_unlink("/sensor_connection_" + itoa(i, NULL, 10));
    }
    free(semaphores);
    free(medians->medians);
    free(medians);

    close(logfileno(logopen("sensor_program.log", "w", LOG_PID)));
    return 0;
