class LongestCommonSubsequence {
  constructor(word1, word2) {
    if (typeof word1 !== 'string' || typeof word2 !== 'string') {
      throw new Error('Both inputs must be strings');
    }

    if (word1.length === 0 || word2.length === 0) {
      throw new Error('Both inputs must be non-empty strings');
    }

    this.word1 = word1;
    this.word2 = word2;
  }

  longestCommonSubsequence() {
    const m = this.word1.length;
    const n = this.word2.length;

    const dp = Array(m + 1)
      .fill(0)
      .map(() => Array(n + 1).fill(0));

    for (let i = 1; i <= m; i++) {
      for (let j = 1; j <= n; j++) {
        if (this.word1[i - 1] === this.word2[j - 1]) {
          dp[i][j] = dp[i - 1][j - 1] + 1;
        } else {
          dp[i][j] = Math.max(dp[i - 1][j], dp[i][j - 1]);
        }
      }
    }

    let lcs = '';
    let i = m;
    let j = n;
    while (i > 0 && j > 0) {
      if (this.word1[i - 1] === this.word2[j - 1]) {
        lcs = this.word1[i - 1] + lcs;
        i--;
        j--;
      } else if (dp[i - 1][j] > dp[i][j - 1]) {
        i--;
      } else {
        j--;
      }
    }

    return lcs;
  }
}

// Example usage:
const word1 = 'ABCBDAB';
const word2 = 'BDCABA';
const lcs = new LongestCommonSubsequence(word1, word2);
console.log(`Longest Common Subsequence: ${lcs.longestCommonSubsequence()}`);
