using namespace std;

class Book {
public:
    string title;
    int edition;
    string author;

    Book(string t, int e, string a) : title(t), edition(e), author(a) {}
};

class Library {
private:
    vector<Book> books;
    vector<string> titles;

public:
    void addBook(string title, int edition, string author) {
        if (find(titles.begin(), titles.end(), title) != titles.end()) {
            cout << "Book with the same title already exists." << endl;
            return;
        }
        books.push_back(Book(title, edition, author));
        titles.push_back(title);
    }

    void removeBook(string title) {
        auto it = find(titles.begin(), titles.end(), title);
        if (it == titles.end()) {
            cout << "Book not found." << endl;
            return;
        }
        titles.erase(it);
        for (auto& book : books) {
            if (book.title == title) {
                books.erase(&book);
                break;
            }
        }
    }

    void listBooks() {
        for (const auto& book : books) {
            cout << "Title: " << book.title << ", Edition: " << book.edition << ", Author: " << book.author << endl;
        }
    }

    void searchBook(string title) {
        auto it = lower_bound(titles.begin(), titles.end(), title);
        if (it == titles.end()) {
            cout << "Book not found." << endl;
            return;
        }
        for (const auto& book : books) {
            if (book.title == *it) {
                cout << "Title: " << book.title << ", Edition: " << book.edition << ", Author: " << book.author << endl;
                break;
            }
        }
    }
};

int main() {
    Library library;
    while (true) {
        cout << "1. Add Book" << endl;
        cout << "2. Remove Book" << endl;
        cout << "3. List Books" << endl;
        cout << "4. Search Book" << endl;
