                string title, author;
                int edition;
                cout << "Enter book title: ";
                cin >> title;
                cout << "Enter book edition: ";
                cin >> edition;
                cout << "Enter book author: ";
                cin >> author;
                library.addBook(title, edition, author);
                break;
            }
            case 2: {
                string title;
                cout << "Enter book title to remove: ";
                cin >> title;
                library.removeBook(title);
                break;
            }
            case 3: {
                library.listBooks();
                break;
