#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <math.h>

#define MAX_SENSORS 10
#define MAX_DATA_POINTS 1000
#define AVG_WINDOW 600  // 10 minutes in seconds

typedef struct {
    double temperature;
    time_t timestamp;
} SensorReading;

SensorReading readings[MAX_SENSORS][MAX_DATA_POINTS];

void add_reading(int sensor_id, double temp) {
    int index = sensor_id * MAX_DATA_POINTS;
    int data_point_index = index + 1;

    // Check for data point index out of bounds
    if (data_point_index >= MAX_DATA_POINTS) {
        printf("Error: Data point index out of bounds\n");
        return;
    }

    // Check for sensor index out of bounds
    if (sensor_id >= MAX_SENSORS) {
        printf("Error: Sensor index out of bounds\n");
        return;
    }

    // Update timestamp
    time_t current_time = time(NULL);
    readings[sensor_id][data_point_index].timestamp = current_time;
    readings[sensor_id][data_point_index].temperature = temp;
}

double calculate_moving_average(int sensor_id) {
    double sum = 0.0;
    int count = 0;

    // Check for sensor index out of bounds
    if (sensor_id >= MAX_SENSORS) {
        printf("Error: Sensor index out of bounds\n");
        return -1.0;
    }

    // Calculate moving average
    for (int i = MAX_DATA_POINTS - 1; i >= 0; i--) {
        if (readings[sensor_id][i].timestamp >= time(NULL) - AVG_WINDOW) {
            sum += readings[sensor_id][i].temperature;
            count++;
        } else {
            break;
        }
    }

    if (count == 0) {
        printf("Error: No data points within the moving average window\n");
        return -1.0;
    }

    return sum / count;
}

int main() {
    srand(time(NULL));

    for (int i = 0; i < MAX_SENSORS; i++) {
        for (int j = 0; j < MAX_DATA_POINTS; j++) {
            readings[i][j].temperature = 0.0;
            readings[i][j].timestamp = 0;
        }
    }

    while (1) {
        for (int i = 0; i < MAX_SENSORS; i++) {
            double temp = (rand() % 100.0) / 100.0;
            add_reading(i, temp);
        }

        double avg_temp;
        for (int i = 0; i < MAX_SENSORS; i++) {
            avg_temp = calculate_moving_average(i);
            if (avg_temp != -1.0) {
                printf("Sensor %d: Moving Average Temperature = %.2f°C\n", i + 1, avg_temp);
            }
        }
    }

    return 0;
}
