class Node {
    constructor(min, max, key, value) {
        this.min = min;
        this.max = max;
        this.key = key;
        this.value = value;
        this.left = null;
        this.right = null;
        this.height = 1;
    }
}

class BTree {
    constructor(t) {
        this.root = new Node(-Infinity, Infinity, 0, null);
        this.t = t;
    }

    height(node) {
        if (node === null) return 0;
        return node.height;
    }

    updateHeight(node) {
        node.height = 1 + Math.max(this.height(node.left), this.height(node.right));
    }

    leftRotate(x) {
        let y = x.right;
        x.right = y.left;
        y.left = x;
        this.updateHeight(x);
        this.updateHeight(y);
        return y;
    }

    rightRotate(x) {
        let y = x.left;
        x.left = y.right;
        y.right = x;
        this.updateHeight(x);
        this.updateHeight(y);
        return y;
    }

    insert(key, value) {
        this.root = this._insert(this.root, key, value);
    }

    _insert(node, key, value) {
        if (node === null) return new Node(key, key, value, null);
        if (key < node.key) node.left = this._insert(node.left, key, value);
        else if (key > node.key) node.right = this._insert(node.right, key, value);
        else {
            console.log("Duplicate key: " + key);
            return node;
        }
        this.updateHeight(node);
        let balance = this.getBalance(node);
        if (balance > 1 && key < node.left.key) return this.rightRotate(node);
        if (balance < -1 && key > node.right.key) return this.leftRotate(node);
        if (balance > 1 && key > node.left.key) {
            node.left = this.leftRotate(node.left);
            return this.rightRotate(node);
        }
        if (balance < -1 && key < node.right.key) {
            node.right = this.rightRotate(node.right);
            return this.leftRotate(node);
        }
        return node;
    }

    getBalance(node) {
        return this.height(node.left) - this.height(node.right);
    }

    search(key) {
        return this._search(this.root, key);
    }

    _search(node, key) {
        if (node === null || node.key === key) return node.value;
        if (key < node.key) return this._search(node.left, key);
        return this._search(node.right, key);
    }

    delete(key) {
        this.root = this._delete(this.root, key);
    }

    _delete(node, key) {
        if (node === null) return node;
        if (key < node.key) node.left = this._delete(node.left, key);
        else if (key > node.key) node.right = this._delete(node.right, key);
        else {
            if (node.left === null) return node.right;
            if (node.right === null) return node.left;
            let temp = this.getMinValueNode(node.right);
            node.key = temp.key;
            node.value = temp.value;
            node.right = this._delete(node.right, temp.key);
        }
        this.updateHeight(node);
        let balance = this.getBalance(node);
        if (balance > 1 && this.getBalance(node.left) >= 0) return this.rightRotate(node);
        if (balance < -1 && this.getBalance(node.right) <= 0) return this.leftRotate(node);
        if (balance > 1 && this.getBalance(node.left) < 0) {
            node.left = this.leftRotate(node.left);
            return this.rightRotate(node);
        }
        if (balance < -1 && this.getBalance(node.right) > 0) {
            node.right = this.rightRotate(node.right);
            return this.leftRotate(node);
        }
        return node;
    }

    getMinValueNode(node) {
        let current = node;
        while (current.left !== null) {
            current = current.left;
        }
        return current;
    }
}

class Book {
