class TopKUsers {
public:
    void addActivity(const string& userId, int timestamp) {
        if (users.find(userId) != users.end()) {
            users[userId].push_back(timestamp);
        } else {
            users[userId] = {timestamp};
        }
    }

    vector<string> getTopKUsers(int k) {
        priority_queue<pair<int, string>> pq;
        for (const auto& pair : users) {
            pq.push({pair.second.size(), pair.first});
        }

        vector<string> topKUsers;
        while (k > 0 && !pq.empty()) {
            topKUsers.push_back(pq.top().second);
            pq.pop();
            k--;
        }

        return topKUsers;
    }

private:
    map<string, vector<int>> users;
};

