fn is_valid(board: &Vec<Vec<bool>>, row: usize, col: usize) -> bool {
    for i in 0..row {
        if board[i][col] {
            return false;
        }
        let mut j = col;
        while i < row && j < board.len() {
            if board[i][j] {
                return false;
            }
            i += 1;
            j += 1;
        }
    }
    true
}

fn solve_n_queens(n: usize, row: usize, board: &mut Vec<Vec<bool>>, result: &mut Vec<Vec<Vec<bool>>>) {
    if row == n {
        result.push(board.clone());
        return;
    }
    for col in 0..n {
        if is_valid(board, row, col) {
            board[row][col] = true;
            solve_n_queens(n, row + 1, board, result);
            board[row][col] = false;
        }
    }
}

fn main() {
    print!("Enter the size of the board: ");
    let mut input = String::new();
    std::io::stdin().read_line(&mut input).expect("Failed to read input");
    let n: usize = input.trim().parse().expect("Invalid input");

    if n < 1 {
        println!("Board size must be a positive integer.");
        return;
    }

    let mut board = vec![vec![false; n]; n];
    let mut result = Vec::new();
    solve_n_queens(n, 0, &mut board, &mut result);

    if result.is_empty() {
        println!("No solution exists.");
    } else {
        println!("Solutions:");
        for (i, solution) in result.into_iter().enumerate() {
            println!("Solution {}: {:?}", i + 1, solution);
        }
    }
}
