class DisjointSet:
    def __init__(self, vertices):
        self.parent = {v: v for v in vertices}
        self.rank = {v: 0 for v in vertices}

    def find(self, vertex):
        if self.parent[vertex] != vertex:
            self.parent[vertex] = self.find(self.parent[vertex])
        return self.parent[vertex]

    def union(self, vertex1, vertex2):
        root1 = self.find(vertex1)
        root2 = self.find(vertex2)

        if root1 != root2:
            if self.rank[root1] > self.rank[root2]:
                self.parent[root2] = root1
            elif self.rank[root1] < self.rank[root2]:
                self.parent[root1] = root2
            else:
                self.parent[root2] = root1
                self.rank[root1] += 1


def read_input_file(filename):
    vertices = set()
    edges = []
    with open(filename, 'r') as file:
        for line in file:
            city, x, y, distance = line.strip().split()
            vertices.add(city)
            edges.append((int(distance), city, city))
    return vertices, edges


def kruskal(edges, vertices):
    edges.sort()
    disjoint_set = DisjointSet(vertices)
    mst = []
    visited = set()

    for edge in edges:
        distance, city1, city2 = edge
        if city1 not in visited or city2 not in visited:
            if disjoint_set.find(city1) != disjoint_set.find(city2):
                disjoint_set.union(city1, city2)
                mst.append(edge)
                visited.add(city1)
                visited.add(city2)

    return mst


def print_mst(mst):
    for edge in mst:
        distance, city1, city2 = edge
        print(f"City {city1} to City {city2}: {distance} units")


def main():
    if len(sys.argv) != 2:
        print("Usage: python program.py <filename>")
        return

    filename = sys.argv[1]
    vertices, edges = read_input_file(filename)
    mst = kruskal(edges, vertices)
    print_mst(mst)


