use std::collections::HashMap;
use std::collections::hash_map::DefaultHasher;
use std::collections::hash_map::Hasher;
use std::collections::hash_map::RandomState;
use std::collections::hash_map::Entry;

// Define a struct to represent a Trie node
struct TrieNode {
    children: HashMap<String, TrieNode>,
    is_end_of_word: bool,
}

impl TrieNode {
    // Create a new Trie node
    fn new() -> TrieNode {
        TrieNode {
            children: HashMap::new(),
            is_end_of_word: false,
        }
    }
}

// Define a struct to represent the Trie
struct Trie {
    root: TrieNode,
}

impl Trie {
    // Create a new Trie
    fn new() -> Trie {
        Trie {
            root: TrieNode::new(),
        }
    }

    // Insert a word into the Trie
    fn insert(&mut self, word: &str) {
        let mut current = self.root;
        for c in word.chars() {
            let child = current.children.entry(c.to_string()).or_insert(TrieNode::new());
            current = child;
        }
        current.is_end_of_word = true;
    }

    // Get all words that match a prefix
    fn get_prefix_matches(&self, prefix: &str) -> Vec<String> {
        let mut current = self.root;
        for c in prefix.chars() {
            let child = current.children.get(&c.to_string());
            if child.is_none() {
                return Vec::new();
            }
            current = child.unwrap();
        }
        self._get_prefix_matches_helper(&mut current, prefix, Vec::new())
    }

    // Helper function to get all words that match a prefix
    fn _get_prefix_matches_helper(&self, current: &TrieNode, prefix: &str, matches: &mut Vec<String>) {
        if current.is_end_of_word {
            matches.push(prefix.to_string());
        }
        for (c, child) in current.children.iter() {
            self._get_prefix_matches_helper(child, prefix + c, matches);
        }
    }
}

fn main() {
    // Create a new Trie
    let mut trie = Trie::new();

    // Insert some words into the Trie
    trie.insert("apple");
    trie.insert("app");
    trie.insert("banana");
    trie.insert("band");

    // Get all words that match a prefix
    let prefix = "ap";
    let matches = trie.get_prefix_matches(prefix);
    println!("Words that match the prefix '{}': {:?}", prefix, matches);

    // Update the Trie with new entries
    trie.insert("applet");
    trie.insert("application");

    // Get all words that match a prefix
    let prefix = "ap";
    let matches = trie.get_prefix_matches(prefix);
    println!("Words that match the prefix '{}': {:?}", prefix, matches);
