class TrieNode {
    constructor() {
        this.children = {};
        this.isEndOfWord = false;
    }
}

class SuffixTree {
    constructor(string) {
        this.root = new TrieNode();
        this.string = string;
    }

    insert(suffix) {
        let node = this.root;
        for (let char of suffix) {
            if (!(char in node.children)) {
                node.children[char] = new TrieNode();
            }
            node = node.children[char];
        }
        node.isEndOfWord = true;
    }

    longestRepeatedSubstring() {
        let maxLength = 0;
        let maxSubstring = "";
        for (let i = 0; i < this.string.length; i++) {
            for (let j = i + 1; j <= this.string.length; j++) {
                let suffix = this.string.substring(i, j);
                this.insert(suffix);
                let node = this.root;
                let currentSubstring = "";
                while (node !== null) {
                    if (node.isEndOfWord) {
                        currentSubstring = suffix + currentSubstring;
                    }
                    node = node.children[this.string[currentSubstring.length]];
                    if (node === null) {
                        break;
                    }
                }
                if (currentSubstring.length > maxLength) {
                    maxLength = currentSubstring.length;
                    maxSubstring = currentSubstring;
                }
                this.root = this.root.children;
            }
        }
        return maxSubstring;
    }
}

