        } else {
            Node newNode = new Node(title);
            newNode.prev = tail;
            tail.next = newNode;
            tail = newNode;
        }
        size++;
    }

    public void removeSong(String title) {
        if (size == 0) {
            return;
        }

        if (head.title.equals(title)) {
            head = head.next;
            if (head != null) {
                head.prev = null;
            } else {
                tail = null;
            }
            size--;
            return;
        }

        Node currentNode = head;
        while (currentNode.next != null) {
            if (currentNode.next.title.equals(title)) {
                currentNode.next = currentNode.next.next;
                if (currentNode.next != null) {
                    currentNode.next.prev = currentNode;
                } else {
                    tail = currentNode;
                }
                size--;
                return;
            }
            currentNode = currentNode.next;
        }
    }

    public void rearrangeSong(String title, int position) {
        if (size == 0) {
            return;
        }

        if (position < 0 || position > size) {
            throw new IndexOutOfBoundsException("Invalid position");
        }

        if (position == 0) {
            if (head.title.equals(title)) {
                return;
            }
            removeSong(head.title);
            addSong(title, position);
            return;
        }

        Node currentNode = head;
        for (int i = 0; i < position - 1; i++) {
            currentNode = currentNode.next;
        }
        removeSong(currentNode.next.title);
        addSong(title, position);
    }

    public void searchSong(String title) {
        Node currentNode = head;
        while (currentNode != null) {
            if (currentNode.title.equals(title)) {
                System.out.println("Song found: " + title);
                return;
            }
            currentNode = currentNode.next;
        }
        System.out.println("Song not found");
    }

    public void displayPlaylist() {
        if (size == 0) {
            System.out.println("Playlist is empty");
            return;
        }

        Node currentNode = head;
        while (currentNode != null) {
            System.out.println(currentNode.title);
            currentNode = currentNode.next;
        }
    }
}

public class PlaylistApp {
