bool isSafe(const std::vector<std::vector<char>>& board, int row, int col, int n) {
    for (int i = 0; i < row; i++) {
        if (board[i][col] == 'Q') {
            return false;
        }
    }

    for (int i = row, j = col; i >= 0 && j >= 0; i--, j--) {
        if (board[i][j] == 'Q') {
            return false;
        }
    }

    for (int i = row, j = col; j >= 0 && i < n; i++, j--) {
        if (board[i][j] == 'Q') {
            return false;
        }
    }

    return true;
}

bool solveNQueensUtil(std::vector<std::vector<char>>& board, int col, int n) {
    if (col >= n) {
        return true;
    }

    for (int i = 0; i < n; i++) {
        if (isSafe(board, i, col, n)) {
            board[i][col] = 'Q';

            if (solveNQueensUtil(board, col + 1, n)) {
                return true;
            }

            board[i][col] = '.';
        }
    }

    return false;
}

bool solveNQueens(std::vector<std::vector<char>>& board, int n) {
    if (n <= 0) {
        return false;
    }

    if (solveNQueensUtil(board, 0, n)) {
        return true;
    }

    return false;
}

void printSolution(const std::vector<std::vector<char>>& board) {
    for (const auto& row : board) {
        for (char cell : row) {
            std::cout << cell << " ";
        }
        std::cout << std::endl;
    }
}

int main() {
    int n;
    std::cout << "Enter the size of the board (n): ";
    std::cin >> n;

    if (n <= 0) {
        std::cout << "Invalid input. Board size should be a positive integer." << std::endl;
        return 1;
    }

    std::vector<std::vector<char>> board(n, std::vector<char>(n, '.'));

    if (solveNQueens(board, n)) {
        std::cout << "Solution exists:" << std::endl;
        printSolution(board);
    } else {
        std::cout << "No solution exists." << std::endl;
    }

    return 0;
}
