import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.util.Arrays;
import java.util.Random;

public class ShellSort {

    public static void main(String[] args) {
        String[] gapSequences = {1, 2, 4, 8, 16, 32, 64, 128, 256};

        for (String gapSequence : gapSequences) {
            System.out.println("Gap sequence: " + gapSequence);
            try {
                int[] salaries = readSalariesFromCSV("salaries.csv");
                if (salaries == null) {
                    System.out.println("No valid salary data found in the CSV file.");
                    continue;
                }

                for (int gap = gapSequence; gap > 0; gap /= 2) {
                    shellSort(salaries, gap);
                }

                System.out.println("Sorted salaries: " + Arrays.toString(salaries));
            } catch (IOException e) {
                System.out.println("Error reading CSV file: " + e.getMessage());
            }
        }
    }

    private static int[] readSalariesFromCSV(String filename) throws IOException {
        try (BufferedReader br = new BufferedReader(new FileReader(filename))) {
            String line;
            int[] salaries = new int[0];

            while ((line = br.readLine()) != null) {
                String[] data = line.split(",");
                if (data.length != 2) {
                    continue;
                }

                try {
                    int salary = Integer.parseInt(data[1].trim());
                    if (salary <= 0) {
                        System.out.println("Invalid salary data: " + salary);
                        continue;
                    }

                    int[] newSalaries = Arrays.copyOf(salaries, salaries.length + 1);
                    newSalaries[salaries.length] = salary;
                    salaries = newSalaries;
                } catch (NumberFormatException e) {
                    System.out.println("Invalid salary data: " + line);
                }
            }

            return salaries;
        }
    }

    private static void shellSort(int[] salaries, int gap) {
        for (int i = gap; i < salaries.length; i++) {
            int temp = salaries[i];
            int j = i;

            while (j >= gap && salaries[j - gap] > temp) {
                salaries[j] = salaries[j - gap];
                j -= gap;
            }

            salaries[j] = temp;
        }
    }
}
