class TabHistory {
    constructor() {
        this.head = null;
        this.tail = null;
        this.current = null;
    }

    openTab(url) {
        let node = new Node(url, this.tail, null);
        if (this.head === null) {
            this.head = node;
            this.tail = node;
            this.current = node;
        } else {
            this.tail.next = node;
            this.tail = node;
            this.current = node;
        }
    }

    closeTab() {
        if (this.current === this.head) {
            this.head = null;
            this.tail = null;
            this.current = null;
        } else {
            this.current.prev.next = null;
            this.tail = this.current.prev;
            this.current = this.current.prev;
        }
    }

    moveForward() {
        if (this.current === this.tail) {
            throw new Error("Cannot move forward when at the latest tab");
        }
        this.current = this.current.next;
    }

    moveBackward() {
        if (this.current === this.head) {
            throw new Error("Cannot move backward when at the first tab");
        }
        this.current = this.current.prev;
    }
}

