// Structure to represent a student record
struct Student {
    std::string name;
    double gpa;
};

// Function to read student records from a file
std::vector<Student> readStudentRecords(const std::string& filename) {
    std::vector<Student> records;
    std::ifstream file(filename);
    if (file.is_open()) {
        std::string line;
        while (std::getline(file, line)) {
            size_t commaPos = line.find(',');
            if (commaPos != std::string::npos) {
                Student student;
                student.name = line.substr(0, commaPos);
                student.gpa = std::stod(line.substr(commaPos + 1));
                records.push_back(student);
            } else {
                std::cerr << "Invalid input line: " << line << std::endl;
            }
        }
        file.close();
    } else {
        std::cerr << "Unable to open file: " << filename << std::endl;
    }
    return records;
}

// Function to perform selection sort
void selectionSort(std::vector<Student>& records) {
    for (size_t i = 0; i < records.size(); ++i) {
        size_t minIndex = i;
        for (size_t j = i + 1; j < records.size(); ++j) {
            if (records[j].gpa > records[minIndex].gpa) {
                minIndex = j;
            }
        }
        // Swap records[i] and records[minIndex]
        std::swap(records[i], records[minIndex]);
    }
}

// Function to print student records
void printStudentRecords(const std::vector<Student>& records) {
    for (const auto& student : records) {
        std::cout << student.name << ": " << student.gpa << std::endl;
    }
}

int main() {
    const std::string filename = "student_records.txt";
    std::vector<Student> records = readStudentRecords(filename);
    if (records.empty()) {
        std::cout << "No student records found." << std::endl;
        return 1;
    }
    selectionSort(records);
    printStudentRecords(records);
    return 0;
}
