class PerfectHash {
    constructor(size) {
        this.size = size;
        this.table = new Array(size).fill(0);
        this.map = new Map();
    }

    _hash(word) {
        let hash = 0;
        for (let i = 0; i < word.length; i++) {
            hash += word.charCodeAt(i);
        }
        return hash % this.size;
    }

    insert(word) {
        let index = this._hash(word);
        if (this.table[index] === 0) {
            this.table[index] = word;
            this.map.set(word, index);
            return true;
        } else {
            return false;
        }
    }

    delete(word) {
        let index = this.map.get(word);
        if (index !== undefined) {
            this.table[index] = 0;
            this.map.delete(word);
            return true;
        } else {
            return false;
        }
    }

    lookup(word) {
        let index = this._hash(word);
        if (this.table[index] !== 0) {
            return this.table[index];
        } else {
            return undefined;
        }
    }
}

class Dictionary {
    constructor() {
        this.perfectHash = new PerfectHash(1000000);
    }

    add(word) {
        return this.perfectHash.insert(word);
    }

    delete(word) {
        return this.perfectHash.delete(word);
    }

    lookup(word) {
        return this.perfectHash.lookup(word);
    }
}

// Example usage:
let dictionary = new Dictionary();
dictionary.add('hello');
dictionary.add('world');
console.log(dictionary.lookup('hello'));  // Output: hello
console.log(dictionary.lookup('world'));  // Output: world
console.log(dictionary.lookup('foo'));    // Output: undefined
