import java.util.*;

class Node {
    int score;
    Node left;
    Node right;

    public Node(int score) {
        this.score = score;
        this.left = null;
        this.right = null;
    }
}

class Leaderboard {
    Node root;

    public Leaderboard() {
        this.root = null;
    }

    public void insert(int score) {
        root = insertNode(root, score);
    }

    public void delete(int score) {
        root = deleteNode(root, score);
    }

    public int kthHighest(int k) {
        return kthHighestNode(root, k);
    }

    private Node insertNode(Node node, int score) {
        if (node == null) {
            return new Node(score);
        }

        if (score > node.score) {
            node.right = insertNode(node.right, score);
        } else {
            node.left = insertNode(node.left, score);
        }

        return node;
    }

    private Node deleteNode(Node node, int score) {
        if (node == null) {
            return null;
        }

        if (score > node.score) {
            node.right = deleteNode(node.right, score);
        } else if (score < node.score) {
            node.left = deleteNode(node.left, score);
        } else {
            if (node.left == null) {
                return node.right;
            } else if (node.right == null) {
                return node.left;
            }

            Node temp = minValueNode(node.right);
            node.score = temp.score;
            node.right = deleteNode(node.right, temp.score);
        }

        return node;
    }

    private int kthHighestNode(Node node, int k) {
        if (node == null) {
            return -1;
        }

        if (node.left == null && node.right == null) {
            return node.score;
        }

        int count = 0;
        if (node.right != null) {
            count += kthHighestNode(node.right, k);
        }

        if (count == 0) {
            return kthHighestNode(node.left, k - 1);
        } else {
            return -1;
        }
    }

    private Node minValueNode(Node node) {
        Node current = node;

        while (current.left != null) {
            current = current.left;
        }

        return current;
    }
}

public class Main {
    public static void main(String[] args) {
        Leaderboard leaderboard = new Leaderboard();

        leaderboard.insert(10);
        leaderboard.insert(20);
        leaderboard.insert(30);
        leaderboard.insert(40);
        leaderboard.insert(50);

        System.out.println(leaderboard.kthHighest(2));  // Output: 30
        leaderboard.delete(20);
        System.out.println(leaderboard.kthHighest(2));  // Output: 30
    }
}
