// Node structure for the skip list
struct Node {
    std::string symbol;
    double price;
    Node* next[5]; // 5 levels in the skip list
};

// Skip list class
class SkipList {
private:
    int maxLevel;
    Node* head;
    int level;

public:
    // Constructor
    SkipList(int maxLevel = 16) {
        this->maxLevel = maxLevel;
        this->head = new Node();
        this->head->next[0] = this->head;
        for (int i = 1; i <= maxLevel; i++) {
            this->head->next[i] = this->head;
        }
        this->level = 1;
    }

    // Insert a new stock price
    void insert(const std::string& symbol, double price) {
        Node* newNode = new Node();
        newNode->symbol = symbol;
        newNode->price = price;

        int level = this->getLevel();
        newNode->next[0] = this->head;
        for (int i = 1; i < level; i++) {
            newNode->next[i] = newNode->next[i - 1]->next[i - 1];
        }

        for (int i = level - 1; i >= 0; i--) {
            while (newNode->next[i]->price < price) {
                newNode = newNode->next[i];
            }
            newNode->next[i + 1] = newNode->next[i]->next[i + 1];
            newNode->next[i] = newNode->next[i]->next[i];
        }
        this->level = std::max(level, this->maxLevel);
    }

    // Delete a stock price
    void deleteSymbol(const std::string& symbol) {
        Node* current = this->head;
        for (int i = 0; i < this->level; i++) {
            current = current->next[i];
        }
        if (current->symbol == symbol) {
            for (int i = 0; i < this->level; i++) {
                if (current->next[i] == this->head->next[i]) {
                    current->next[i] = current->next[i + 1];
                } else {
                    Node* prev = current->next[i - 1];
                    Node* next = current->next[i + 1];
                    while (next != this->head->next[i + 1]) {
                        prev = next;
                        next = next->next[i + 1];
                    }
                    prev->next[i] = next;
                    delete current;
                    this->level = std::max(this->level - 1, this->maxLevel);
                    return;
                }
            }
        }
    }

    // Search for a stock price
    bool search(const std::string& symbol) {
        Node* current = this->head;
        for (int i = 0; i < this->level; i++) {
            current = current->next[i];
        }
        if (current->symbol == symbol) {
            return true;
        }
        return false;
    }

    // Get the level of the skip list
    int getLevel() {
        return rand() % (this->maxLevel + 1);
    }

    // Get the sorted list of stocks by price
    void getSortedList() {
        std::list<std::string> sortedSymbols;
        Node* current = this->head;
        for (int i = this->level - 1; i >= 0; i--) {
            current = current->next[i];
            while (current != this->head->next[i]) {
                sortedSymbols.push_back(current->symbol);
                current = current->next[i];
            }
        }
        std::cout << "Sorted List of Stocks by Price:" << std::endl;
        for (const auto& symbol : sortedSymbols) {
            std::cout << symbol << ": " << symbol << std::endl;
        }
    }
};

int main() {
    srand(time(0));
    SkipList skipList;

    // Insert stock prices
    skipList.insert("AAPL", 150.0);
    skipList.insert("GOOG", 2500.0);
    skipList.insert("MSFT", 200.0);
    skipList.insert("AMZN", 3000.0);

    // Search for a stock price
    std::cout << "Is 'GOOG' in the list? " << (skipList.search("GOOG") ? "Yes" : "No") << std::endl;

    // Delete a stock price
    skipList.deleteSymbol("MSFT");

    // Get the sorted list of stocks by price
    skipList.getSortedList();

    return 0;
}
