use std::collections::BinaryHeap;

// Define a Task struct to hold task details
struct Task {
    id: i32,
    priority: i32,
}

// Implement Ord for Task to enable BinaryHeap
impl std::cmp::Ord for Task {
    fn cmp(&self, other: &Task) -> std::cmp::Ordering {
        self.priority.cmp(&other.priority)
    }
}

// Implement PartialOrd for Task to enable BinaryHeap
impl std::cmp::PartialOrd for Task {
    fn partial_cmp(&self, other: &Task) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

// Define a TaskScheduler struct to manage tasks
struct TaskScheduler {
    heap: BinaryHeap<Task>,
}

impl TaskScheduler {
    // Create a new TaskScheduler
    fn new() -> TaskScheduler {
        TaskScheduler {
            heap: BinaryHeap::new(),
        }
    }

    // Insert a new task into the scheduler
    fn insert_task(&mut self, id: i32, priority: i32) {
        self.heap.push(Task { id, priority });
    }

    // Update the priority of an existing task
    fn update_task_priority(&mut self, id: i32, new_priority: i32) {
        let mut task = self.heap.pop().unwrap();
        task.priority = new_priority;
        self.heap.push(task);
    }

    // Fetch the highest-priority task from the scheduler
    fn fetch_highest_priority_task(&self) -> Option<&Task> {
        self.heap.peek()
    }
}

fn main() {
    let mut scheduler = TaskScheduler::new();

    // Insert tasks
    scheduler.insert_task(1, 3);
    scheduler.insert_task(2, 1);
    scheduler.insert_task(3, 2);

    // Update task priority
    scheduler.update_task_priority(2, 4);

    // Fetch highest-priority task
    match scheduler.fetch_highest_priority_task() {
        Some(task) => println!("Highest priority task: ID={} Priority={}", task.id, task.priority),
        None => println!("No tasks in the scheduler"),
    }
}
