class Node {
    constructor(key, value) {
        this.key = key;
        this.value = value;
        this.height = 1;
        this.left = null;
        this.right = null;
        this.count = 1;
    }
}

class AVLTree {
    constructor() {
        this.root = null;
    }

    insert(key, value) {
        this.root = this._insert(this.root, key, value);
    }

    _insert(node, key, value) {
        if (!node) return new Node(key, value);
        if (key < node.key) {
            node.left = this._insert(node.left, key, value);
        } else if (key > node.key) {
            node.right = this._insert(node.right, key, value);
        } else {
            node.value = value;
        }

        node.count = 1 + this._count(node.left) + this._count(node.right);

        let balanceFactor = this._balanceFactor(node);
        if (balanceFactor > 1) {
            if (key < node.left.key) {
                return this._rotateRight(node);
            } else {
                node.left = this._rotateLeft(node.left);
                return this._rotateRight(node);
            }
        }
        if (balanceFactor < -1) {
            if (key > node.right.key) {
                return this._rotateLeft(node);
            } else {
                node.right = this._rotateRight(node.right);
                return this._rotateLeft(node);
            }
        }
        return node;
    }

    _count(node) {
        if (!node) return 0;
        return node.count;
    }

    _balanceFactor(node) {
        if (!node) return 0;
        return this._height(node.left) - this._height(node.right);
    }

    _height(node) {
        if (!node) return 0;
        return node.height;
    }

    _rotateLeft(node) {
        let temp = node.right;
        node.right = temp.left;
        temp.left = node;

        node.height = Math.max(this._height(node.left), this._height(node.right)) + 1;
        temp.height = Math.max(this._height(temp.left), this._height(temp.right)) + 1;

        return temp;
    }

    _rotateRight(node) {
        let temp = node.left;
        node.left = temp.right;
        temp.right = node;

        node.height = Math.max(this._height(node.left), this._height(node.right)) + 1;
        temp.height = Math.max(this._height(temp.left), this._height(temp.right)) + 1;

        return temp;
    }

    rank(key) {
        return this._rank(this.root, key);
    }

    _rank(node, key) {
        if (!node) return 0;
        if (key < node.key) {
            return this._rank(node.left, key);
        } else if (key > node.key) {
            return 1 + this._count(node.left) + this._rank(node.right, key);
        } else {
            return this._count(node.left);
        }
    }
}

class Leaderboard {
    constructor() {
        this.tree = new AVLTree();
    }

    insert(user, score) {
        this.tree.insert(user, score);
    }

    rank(user) {
        return this.tree.rank(user);
    }
}

module.exports = Leaderboard;
