#include <stdexcept>

using namespace std;

// Custom Exception for Order Validation
class InvalidOrderException : public runtime_error {
public:
    InvalidOrderException(string message) : runtime_error(message) {}
};

// Custom Exception for Duplicate Price Levels
class DuplicatePriceLevelException : public runtime_error {
public:
    DuplicatePriceLevelException(string message) : runtime_error(message) {}
};

// Node class representing a node in the AVL tree
class Node {
public:
    int price;
    int quantity;
    Node* left;
    Node* right;
    int height;

    Node(int price, int quantity) : price(price), quantity(quantity), left(nullptr), right(nullptr), height(1) {}
};

// AVL tree class
class AVLTree {
private:
    Node* root;

public:
    AVLTree() : root(nullptr) {}

    // Insert a new order into the AVL tree
    void insert(int price, int quantity) {
        root = insertRecursive(root, price, quantity);
    }

    // Recursively insert a new order into the AVL tree
    Node* insertRecursive(Node* node, int price, int quantity) {
        if (node == nullptr) {
            return new Node(price, quantity);
        }

        if (price < node->price) {
            node->left = insertRecursive(node->left, price, quantity);
        } else if (price > node->price) {
            node->right = insertRecursive(node->right, price, quantity);
        } else {
            throw DuplicatePriceLevelException("Duplicate price level found.");
        }

        node->height = max(getHeight(node->left), getHeight(node->right)) + 1;
        int balance = getBalance(node);

        if (balance > 1 && price < node->left->price) {
            return rightRotate(node);
        }
        if (balance < -1 && price > node->right->price) {
            return leftRotate(node);
        }
        if (balance > 1 && price >= node->left->price) {
            node->left = leftRotate(node->left);
            return rightRotate(node);
        }
        if (balance < -1 && price <= node->right->price) {
            node->right = rightRotate(node->right);
            return leftRotate(node);
        }

        return node;
    }

    // Delete an order from the AVL tree
    void deleteOrder(int price) {
        root = deleteRecursive(root, price);
    }

    // Recursively delete an order from the AVL tree
    Node* deleteRecursive(Node* node, int price) {
        if (node == nullptr) {
            return node;
        }

        if (price < node->price) {
            node->left = deleteRecursive(node->left, price);
        } else if (price > node->price) {
            node->right = deleteRecursive(node->right, price);
        } else {
            if (node->left == nullptr) {
                return node->right;
            } else if (node->right == nullptr) {
                return node->left;
            }

            Node* temp = minValueNode(node->right);
            node->price = temp->price;
            node->quantity = temp->quantity;
            node->right = deleteRecursive(node->right, temp->price);
        }

        if (node == nullptr) {
            return node;
        }

        node->height = max(getHeight(node->left), getHeight(node->right)) + 1;
        int balance = getBalance(node);

        if (balance > 1 && getBalance(node->left) >= 0) {
            return rightRotate(node);
        }
        if (balance < -1 && getBalance(node->right) <= 0) {
            return leftRotate(node);
        }
        if (balance > 1 && getBalance(node->left) < 0) {
            node->left = leftRotate(node->left);
            return rightRotate(node);
        }
        if (balance < -1 && getBalance(node->right) > 0) {
            node->right = rightRotate(node->right);
            return leftRotate(node);
        }

        return node;
    }

    // Get the minimum value node in the AVL tree
    Node* minValueNode(Node* node) {
        while (node->left != nullptr) {
            node = node->left;
        }
        return node;
    }

    // Get the height of a node in the AVL tree
    int getHeight(Node* node) {
        if (node == nullptr) {
            return 0;
        }
        return node->height;
    }

    // Get the balance factor of a node in the AVL tree
    int getBalance(Node* node) {
        if (node == nullptr) {
            return 0;
        }
        return getHeight(node->left) - getHeight(node->right);
    }

    // Left rotate a node in the AVL tree
    Node* leftRotate(Node* z) {
        Node* y = z->right;
        Node* T2 = y->left;

        y->left = z;
        z->right = T2;

        z->height = max(getHeight(z->left), getHeight(z->right)) + 1;
        y->height = max(getHeight(y->left), getHeight(y->right)) + 1;

        return y;
    }

    // Right rotate a node in the AVL tree
    Node* rightRotate(Node* z) {
        Node* y = z->left;
        Node* T2 = y->right;

        y->right = z;
        z->left = T2;

        z->height = max(getHeight(z->left), getHeight(z->right)) + 1;
        y->height = max(getHeight(y->left), getHeight(y->right)) + 1;

        return y;
    }

    // Print the AVL tree in in-order traversal
    void printInOrder() {
        printInOrderRecursive(root);
    }

    // Recursively print the AVL tree in in-order traversal
    void printInOrderRecursive(Node* node) {
        if (node != nullptr) {
            printInOrderRecursive(node->left);
            cout << "Price: " << node->price << ", Quantity: " << node->quantity << endl;
            printInOrderRecursive(node->right);
        }
    }
};

int main() {
    AVLTree orderBook;

    try {
        // Insert orders
        orderBook.insert(100, 10);
        orderBook.insert(90, 20);
        orderBook.insert(110, 30);

        // Print the order book
        cout << "Order Book:" << endl;
        orderBook.printInOrder();

        // Delete an order
        orderBook.deleteOrder(100);

        // Print the updated order book
        cout << "\nUpdated Order Book:" << endl;
        orderBook.printInOrder();
    } catch (const exception& e) {
        cerr << "Error: " << e.what() << endl;
    }

    return 0;
}
