// Trie node
struct TrieNode {
    children: HashMap<char, TrieNode>,
    is_word: bool,
}

impl TrieNode {
    fn new() -> TrieNode {
        TrieNode {
            children: HashMap::new(),
            is_word: false,
        }
    }
}

// Trie
struct Trie {
    root: TrieNode,
}

impl Trie {
    fn new() -> Trie {
        Trie { root: TrieNode::new() }
    }

    fn insert(&mut self, word: &str) {
        let mut node = &mut self.root;
        for c in word.chars() {
            if !node.children.contains_key(&c) {
                node.children.insert(c, TrieNode::new());
            }
            node = &mut node.children[&c];
        }
        node.is_word = true;
    }

    fn search(&self, word: &str) -> bool {
        let mut node = &self.root;
        for c in word.chars() {
            if !node.children.contains_key(&c) {
                return false;
            }
            node = &node.children[&c];
        }
        node.is_word
    }

    fn starts_with(&self, prefix: &str) -> Vec<String> {
        let mut node = &self.root;
        for c in prefix.chars() {
            if !node.children.contains_key(&c) {
                return Vec::new();
            }
            node = &node.children[&c];
        }
        self._starts_with(node, prefix)
    }

    fn _starts_with(&self, node: &TrieNode, prefix: &str) -> Vec<String> {
        let mut result = Vec::new();
        if node.is_word {
            result.push(prefix.to_string());
        }
        for (c, child) in &node.children {
            result.extend(self._starts_with(child, prefix + c));
        }
        result
    }
}

fn load_words(file_path: &str) -> Vec<String> {
    let file = File::open(file_path).expect("Failed to open file");
    let reader = BufReader::new(file);
    reader.lines().map(|line| line.expect("Failed to read line")).collect()
}

