use std::collections::HashMap;
use std::sync::{Arc, Mutex};
use std::thread;

// Define a struct to represent a task
struct Task {
    id: usize,
    priority: u32,
    description: String,
}

impl Task {
    // Create a new task
    fn new(id: usize, priority: u32, description: String) -> Self {
        Task { id, priority, description }
    }
}

// Define a struct to represent a node in the doubly linked list
struct Node<T> {
    data: T,
    prev: Option<Box<Node<T>>>,
    next: Option<Box<Node<T>>>,
}

impl<T> Node<T> {
    // Create a new node
    fn new(data: T) -> Self {
        Node {
            data,
            prev: None,
            next: None,
        }
    }
}

// Define a struct to represent the task list
struct TaskList {
    head: Option<Box<Node<Task>>>,
    tail: Option<Box<Node<Task>>>,
    task_map: Arc<Mutex<HashMap<usize, usize>>>,
}

impl TaskList {
    // Create a new task list
    fn new() -> Self {
        TaskList {
            head: None,
            tail: None,
            task_map: Arc::new(Mutex::new(HashMap::new())),
        }
    }

    // Insert a task into the task list
    fn insert(&self, task: Task) {
        let new_node = Box::new(Node::new(task));
        if self.head.is_none() {
            self.head = Some(new_node);
            self.tail = Some(new_node);
        } else {
            self.tail.as_mut().unwrap().next = Some(new_node);
            new_node.prev = self.tail.as_mut().unwrap();
            self.tail = Some(new_node);
        }
        *self.task_map.lock().unwrap().entry(task.id).or_insert(0) = self.tail.as_ref().unwrap().id;
    }

    // Remove a task from the task list
    fn remove(&self, id: usize) {
        if let Some(node) = self.head.as_ref() {
            if node.data.id == id {
                self.head = node.next.take();
                if self.head.is_none() {
                    self.tail = None;
                }
                *self.task_map.lock().unwrap().get_mut(&id).unwrap() = 0;
                return;
            }
            let mut current = node;
            while current.as_ref().map_or(false, |n| n.next.is_some()) {
                if current.as_ref().map_or(false, |n| n.data.id == id) {
                    current.as_mut().unwrap().next = current.as_mut().unwrap().next.take();
                    if current.as_mut().unwrap().next.is_none() {
                        self.tail = current.as_mut().unwrap();
                    }
                    *self.task_map.lock().unwrap().get_mut(&id).unwrap() = 0;
                    return;
                }
                current = current.as_mut().unwrap().next.as_ref().unwrap();
            }
        }
    }

    // Get a task from the task list
    fn get(&self, id: usize) -> Option<&Task> {
        if let Some(node) = self.head.as_ref() {
            if node.data.id == id {
                return Some(&node.data);
            }
            let mut current = node;
            while current.as_ref().map_or(false, |n| n.next.is_some()) {
                if current.as_ref().map_or(false, |n| n.data.id == id) {
                    return Some(&current.as_ref().unwrap().data);
                }
                current = current.as_ref().unwrap().next.as_ref().unwrap();
            }
        }
        None
    }
}

fn main() {
    let mut task_list = TaskList::new();

    let handle1 = thread::spawn(move || {
        task_list.insert(Task::new(1, 1, String::from("Task 1")));
        task_list.insert(Task::new(2, 2, String::from("Task 2")));
        task_list.insert(Task::new(3, 3, String::from("Task 3")));
    });

    let handle2 = thread::spawn(move || {
        task_list.insert(Task::new(4, 4, String::from("Task 4")));
        task_list.insert(Task::new(5, 5, String::from("Task 5")));
    });

    handle1.join().unwrap();
    handle2.join().unwrap();

    println!("Task 1: {:?}", task_list.get(1));
    println!("Task 2: {:?}", task_list.get(2));
    println!("Task 3: {:?}", task_list.get(3));
    println!("Task 4: {:?}", task_list.get(4));
    println!("Task 5: {:?}", task_list.get(5));

    task_list.remove(2);
    println!("Task 2: {:?}", task_list.get(2));
}
