struct Employee {
    std::string name;
    double performanceScore;

    // Constructor to initialize employee data
    Employee(const std::string& name, double performanceScore)
        : name(name), performanceScore(performanceScore) {}
};

// Function to perform insertion sort on a vector of Employee
void insertionSort(std::vector<Employee>& employees) {
    for (size_t i = 1; i < employees.size(); ++i) {
        Employee current = employees[i];
        int j = i - 1;

        // Shift elements to the right until a smaller element is found
        while (j >= 0 && employees[j].performanceScore > current.performanceScore) {
            employees[j + 1] = employees[j];
            --j;
        }

        // Insert the current employee at the correct position
        employees[j + 1] = current;
    }
}

// Function to display employee data
void displayEmployees(const std::vector<Employee>& employees) {
    for (const auto& employee : employees) {
        std::cout << "Name: " << employee.name << ", Performance Score: " << employee.performanceScore << std::endl;
    }
}

