#include <iostream>
#include <vector>
#include <algorithm>

// Define a structure to represent a player
struct Player {
    int playerId;
    int score;
};

// Custom comparator for sorting players based on their scores
struct ComparePlayers {
    bool operator()(const Player& a, const Player& b) {
        return a.score < b.score;
    }
};

class Leaderboard {
private:
    std::vector<Player> players;

public:
    // Insert a new player into the leaderboard
    void insertPlayer(int playerId, int score) {
        players.push_back({playerId, score});
        std::sort(players.begin(), players.end(), ComparePlayers());
    }

    // Update the score of an existing player
    void updateScore(int playerId, int newScore) {
        for (auto& player : players) {
            if (player.playerId == playerId) {
                player.score = newScore;
                std::sort(players.begin(), players.end(), ComparePlayers());
                return;
            }
        }
    }

    // Get the top N players from the leaderboard
    std::vector<Player> getTopNPlayers(int n) {
        if (n > players.size()) {
            n = players.size();
        }
        std::vector<Player> topPlayers = players;
        topPlayers.resize(n);
        std::sort(topPlayers.begin(), topPlayers.end(), ComparePlayers());
        return topPlayers;
    }

    // Remove a player from the leaderboard
    void removePlayer(int playerId) {
        players.erase(std::remove_if(players.begin(), players.end(), [playerId](const Player& player) {
            return player.playerId == playerId;
        }), players.end());
    }
};

int main() {
    Leaderboard leaderboard;

    // Insert players into the leaderboard
    leaderboard.insertPlayer(1, 100);
    leaderboard.insertPlayer(2, 50);
    leaderboard.insertPlayer(3, 150);

    // Update scores
    leaderboard.updateScore(2, 75);

    // Get top N players
    std::vector<Player> top3Players = leaderboard.getTopNPlayers(3);
    for (const auto& player : top3Players) {
        std::cout << "Player ID: " << player.playerId << ", Score: " << player.score << std::endl;
    }

    // Remove a player
    leaderboard.removePlayer(2);

    // Get top N players after removal
    std::vector<Player> top3PlayersAfterRemoval = leaderboard.getTopNPlayers(3);
    for (const auto& player : top3PlayersAfterRemoval) {
        std::cout << "Player ID: " << player.playerId << ", Score: " << player.score << std::endl;
    }

    return 0;
}
