import heapq

class PriorityQueue:
    def __init__(self):
        self.heap = []

    def insert(self, task, priority):
        if task in self.heap:
            print(f"Task {task} already exists in the queue.")
            return

        if not isinstance(priority, int) or priority < 0:
            print("Invalid priority. Priority must be a non-negative integer.")
            return

        heapq.heappush(self.heap, (-priority, task))

    def delete(self, task):
        if task not in self.heap:
            print(f"Task {task} does not exist in the queue.")
            return

        self.heap.remove((-self.heap[0][0], task))
        heapq.heapify(self.heap)

    def retrieve(self):
        if not self.heap:
            print("Queue is empty.")
            return

        return self.heap[0][1]

    def size(self):
        return len(self.heap)

def main():
    queue = PriorityQueue()

    # Insert tasks
    queue.insert("Task A", 3)
    queue.insert("Task B", 2)
    queue.insert("Task C", 1)
    queue.insert("Task A", 4)  # Duplicate task

    # Retrieve smallest task
    print("Smallest task:", queue.retrieve())

    # Delete task
    queue.delete("Task B")

    # Retrieve smallest task after deletion
    print("Smallest task after deletion:", queue.retrieve())

