// Function to create a new dynamic array
DynamicArray *dynamic_array_new(int initial_capacity) {
    DynamicArray *da = (DynamicArray *)malloc(sizeof(DynamicArray));
    da->data = (int *)malloc(initial_capacity * sizeof(int));
    da->size = 0;
    da->capacity = initial_capacity;
    return da;
}

// Function to add an element to the dynamic array
void dynamic_array_push(DynamicArray *da, int element) {
    if (da->size == da->capacity) {
        da->capacity *= 2;
        int *new_data = (int *)realloc(da->data, da->capacity * sizeof(int));
        da->data = new_data;
    }
    da->data[da->size++] = element;
}

// Function to get the dynamic array size
int dynamic_array_size(DynamicArray *da) {
    return da->size;
}

// Function to get the dynamic array capacity
int dynamic_array_capacity(DynamicArray *da) {
    return da->capacity;
}

// Function to create a new dynamic array with initial capacity
DynamicArray *dynamic_array_new_with_capacity(int initial_capacity) {
    DynamicArray *da = (DynamicArray *)malloc(sizeof(DynamicArray));
    da->data = (int *)malloc(initial_capacity * sizeof(int));
    da->size = 0;
    da->capacity = initial_capacity;
    return da;
}

// Function to free the dynamic array memory
void dynamic_array_free(DynamicArray *da) {
    free(da->data);
    free(da);
}

// Function to read a file and store its content in a dynamic array
DynamicArray *file_to_dynamic_array(const char *filename) {
    DynamicArray *da = dynamic_array_new_with_capacity(1000);
    FILE *file = fopen(filename, "r");
    if (file == NULL) {
        printf("Error opening file %s\n", filename);
        return NULL;
    }

    char line[1024];
    while (fgets(line, sizeof(line), file)) {
        int length = strlen(line);
        for (int i = 0; i < length; i++) {
            int char_value = line[i];
            dynamic_array_push(da, char_value);
        }
    }

    fclose(file);
    return da;
}

// Function to build a matrix from a dynamic array
void build_matrix_from_dynamic_array(DynamicArray *da, int **matrix) {
    int matrix_size = dynamic_array_size(da);
    int matrix_capacity = dynamic_array_capacity(da);
    matrix = (int **)malloc(matrix_size * sizeof(int *));
    for (int i = 0; i < matrix_size; i++) {
        matrix[i] = (int *)malloc(matrix_capacity * sizeof(int));
    }

    int current_row = 0;
    int current_col = 0;
    for (int i = 0; i < matrix_size; i++) {
        for (int j = 0; j < matrix_capacity; j++) {
            matrix[i][j] = da->data[current_row++];
            if (current_row == matrix_size) {
                current_row = 0;
                current_col++;
            }
        }
    }
}

// Function to find the largest common subsequence using dynamic programming
void largest_common_subsequence(DynamicArray *da, int **matrix) {
    int matrix_size = dynamic_array_size(da);
    int matrix_capacity = dynamic_array_capacity(da);
    int **dp = (int **)malloc(matrix_size * sizeof(int *));
    for (int i = 0; i < matrix_size; i++) {
        dp[i] = (int *)malloc(matrix_capacity * sizeof(int));
    }

    for (int i = 0; i < matrix_size; i++) {
        for (int j = 0; j < matrix_capacity; j++) {
            if (i == 0 || j == 0) {
                dp[i][j] = 0;
            } else if (matrix[i][j] == da->data[0]) {
                dp[i][j] = dp[i - 1][j - 1] + 1;
            } else {
                dp[i][j] = 0;
            }
        }
    }

    int max_length = 0;
    int max_length_index = 0;
    for (int i = 0; i < matrix_size; i++) {
        for (int j = 0; j < matrix_capacity; j++) {
            if (dp[i][j] > max_length) {
                max_length = dp[i][j];
                max_length_index = j;
            }
        }
    }

    printf("Largest Common Subsequence: ");
    for (int i = max_length_index; i >= 0; i--) {
        printf("%d ", da->data[i]);
    }
    printf("\n");
}

int main() {
    DynamicArray *da;
    int **matrix;

    while (1) {
        printf("1. Add a file\n");
        printf("2. Find LCS\n");
        printf("3. Exit\n");
        printf("Choose an option: ");
        int option;
        scanf("%d", &option);

        if (option == 1) {
            const char *filename;
            printf("Enter the filename: ");
            scanf("%s", filename);
            da = file_to_dynamic_array(filename);
            if (da == NULL) {
                continue;
            }
            dynamic_array_free(da);
        } else if (option == 2) {
            if (dynamic_array_size(da) == 0) {
                printf("No files added\n");
                continue;
            }
            build_matrix_from_dynamic_array(da, &matrix);
            largest_common_subsequence(da, matrix);
            for (int i = 0; i < dynamic_array_size(da); i++) {
                dynamic_array_free(dynamic_array_new_with_capacity(1));
            }
            free(matrix);
        } else if (option == 3) {
            break;
        } else {
            printf("Invalid option\n");
        }
    }

    return 0;
}
