#include <time.h>

// Structure to represent a packet
typedef struct Packet {
    char* data;
    int priority;
    struct Packet* next;
} Packet;

// Structure to represent a priority queue
typedef struct PriorityQueue {
    Packet* front;
    Packet* rear;
    int size;
} PriorityQueue;

// Function to create a new packet
Packet* createPacket(char* data, int priority) {
    Packet* packet = (Packet*)malloc(sizeof(Packet));
    packet->data = (char*)malloc(strlen(data) + 1);
    strcpy(packet->data, data);
    packet->priority = priority;
    packet->next = NULL;
    return packet;
}

// Function to create a new priority queue
PriorityQueue* createPriorityQueue() {
    PriorityQueue* queue = (PriorityQueue*)malloc(sizeof(PriorityQueue));
    queue->front = NULL;
    queue->rear = NULL;
    queue->size = 0;
    return queue;
}

// Function to insert a packet into the priority queue
void insertPacket(PriorityQueue* queue, Packet* packet) {
    if (queue->size == 0 || packet->priority < queue->front->priority) {
        packet->next = queue->front;
        if (queue->front != NULL) {
            queue->front = packet;
        } else {
            queue->rear = packet;
        }
        queue->size++;
    } else {
        Packet* current = queue->front;
        while (current->next != NULL && current->next->priority <= packet->priority) {
            current = current->next;
        }
        packet->next = current->next;
        if (current->next != NULL) {
            current->next = packet;
        } else {
            queue->rear = packet;
        }
        queue->size++;
    }
}

// Function to remove the highest priority packet from the queue
Packet* removeFront(PriorityQueue* queue) {
    if (queue->size == 0) {
        return NULL;
    }
    Packet* removedPacket = queue->front;
    if (queue->size == 1) {
        queue->front = NULL;
        queue->rear = NULL;
    } else {
        queue->front = queue->front->next;
    }
    queue->size--;
    return removedPacket;
}

// Function to print the packets in the queue
void printQueue(PriorityQueue* queue) {
    Packet* current = queue->front;
    printf("Priority Queue:\n");
    while (current != NULL) {
        printf("Packet Data: %s, Priority: %d\n", current->data, current->priority);
        current = current->next;
    }
}

// Function to handle packet arrival and scheduling
void schedulePacket(PriorityQueue* queue, char* data, int priority) {
    Packet* packet = createPacket(data, priority);
    insertPacket(queue, packet);
    printf("Packet %s with priority %d scheduled successfully.\n", data, priority);
}

// Function to simulate packet arrival and scheduling
void simulatePacketArrival(int numPackets, int* priorities, char** data) {
    PriorityQueue* queue = createPriorityQueue();
    for (int i = 0; i < numPackets; i++) {
        schedulePacket(queue, data[i], priorities[i]);
        printQueue(queue);
        sleep(1); // Simulate packet processing time
    }
}

int main() {
    int numPackets = 5;
    int* priorities = (int*)malloc(numPackets * sizeof(int));
    char** data = (char**)malloc(numPackets * sizeof(char*));

    priorities[0] = 3;
    priorities[1] = 1;
    priorities[2] = 2;
    priorities[3] = 4;
    priorities[4] = 0;

    data[0] = "Packet 1";
    data[1] = "Packet 2";
    data[2] = "Packet 3";
    data[3] = "Packet 4";
    data[4] = "Packet 5";

    simulatePacketArrival(numPackets, priorities, data);

    return 0;
}
