class PriorityQueue {
    constructor() {
        this.queue = [];
    }

    enqueue([distance, node]) {
        this.queue.push([distance, node]);
        this.sort();
    }

    dequeue() {
        return this.queue.shift();
    }

    sort() {
        this.queue.sort((a, b) => a[0] - b[0]);
    }

    isEmpty() {
        return this.queue.length === 0;
    }
}

function dijkstra(graph, start, end) {
    if (!graph || !start || !end) {
        throw new Error("Invalid input: graph, start, and end must be defined");
    }

    if (!(start in graph) || !(end in graph)) {
        throw new Error("Invalid input: start and end must be valid nodes in the graph");
    }

    const distances = {};
    const previous = {};
    const priorityQueue = new PriorityQueue();

    for (const node in graph) {
        distances[node] = Infinity;
        previous[node] = null;
        priorityQueue.enqueue([0, node]);
    }

    distances[start] = 0;
    priorityQueue.enqueue([0, start]);

    while (!priorityQueue.isEmpty()) {
        const [currentDistance, currentNode] = priorityQueue.dequeue();

        if (currentNode === end) {
            const path = [];
            let tempNode = currentNode;
            while (tempNode !== null) {
                path.push(tempNode);
                tempNode = previous[tempNode];
            }
            return path.reverse();
        }

        if (currentDistance > distances[currentNode]) {
            continue;
        }

        for (const neighbor in graph[currentNode]) {
            const distance = currentDistance + graph[currentNode][neighbor];

            if (distance < distances[neighbor]) {
                distances[neighbor] = distance;
                previous[neighbor] = currentNode;
                priorityQueue.enqueue([distance, neighbor]);
            }
        }
    }

    if (distances[end] === Infinity) {
        throw new Error(`No path found from ${start} to ${end}`);
    }

    return distances;
}

// Example usage
const graph = {
    'A': {'B': 1, 'C': 4},
    'B': {'A': 1, 'C': 2, 'D': 5},
    'C': {'A': 4, 'B': 2, 'D': 1},
    'D': {'B': 5, 'C': 1}
};

console.log(dijkstra(graph, 'A', 'D'));  // Output: [ 'A', 'B', 'C', 'D' ]
