import java.io.File;
import java.io.FileNotFoundException;
import java.util.HashMap;
import java.util.Map;
import java.util.Scanner;
import java.util.TreeMap;

public class ConfigManager {
    private Map<String, String> configMap;
    private TreeMap<String, String> sortedMap;

    public ConfigManager(String filePath) throws FileNotFoundException {
        configMap = new HashMap<>();
        sortedMap = new TreeMap<>();

        loadConfig(filePath);
    }

    private void loadConfig(String filePath) throws FileNotFoundException {
        File file = new File(filePath);
        Scanner scanner = new Scanner(file);

        while (scanner.hasNextLine()) {
            String line = scanner.nextLine().trim();
            if (!line.isEmpty()) {
                String[] parts = line.split("=");
                if (parts.length == 2) {
                    String key = parts[0].trim();
                    String value = parts[1].trim();

                    if (configMap.containsKey(key) && !configMap.get(key).equals(value)) {
                        throw new RuntimeException("Duplicate key: " + key);
                    }

                    configMap.put(key, value);
                    sortedMap.put(key, value);
                } else {
                    throw new RuntimeException("Invalid key-value format: " + line);
                }
            }
        }

        scanner.close();
    }

    public String get(String key) {
        if (sortedMap.containsKey(key)) {
            return configMap.get(key);
        } else {
            throw new RuntimeException("Key not found: " + key);
        }
    }

    public void put(String key, String value) {
        if (configMap.containsKey(key) && !configMap.get(key).equals(value)) {
            throw new RuntimeException("Duplicate key: " + key);
        }

        configMap.put(key, value);
        sortedMap.put(key, value);
    }

    public void reloadConfig(String filePath) throws FileNotFoundException {
        configMap.clear();
        sortedMap.clear();
        loadConfig(filePath);
    }

    public static void main(String[] args) throws FileNotFoundException {
        ConfigManager configManager = new ConfigManager("config.properties");
        configManager.put("key1", "value1");
        configManager.put("key2", "value2");

        System.out.println(configManager.get("key1"));  // Output: value1
        System.out.println(configManager.get("key2"));  // Output: value2

        configManager.reloadConfig("config.properties");
        System.out.println(configManager.get("key1"));  // Output: value1
        System.out.println(configManager.get("key2"));  // Output: value2
    }
}
