using namespace std;

// Function to check if a queen can be placed at position (row, col) on the board
bool isValidMove(int board[8][8], int row, int col) {
    // Check the column
    for (int i = 0; i < 8; i++) {
        if (board[i][col] == 1) {
            return false;
        }
    }
    // Check the upper-left diagonal
    for (int i = row, j = col; i >= 0 && j >= 0; i--, j--) {
        if (board[i][j] == 1) {
            return false;
        }
    }
    // Check the upper-right diagonal
    for (int i = row, j = col; i >= 0 && j < 8; i--, j++) {
        if (board[i][j] == 1) {
            return false;
        }
    }
    return true;
}

// Recursive function to solve the 8-Queens problem using backtracking
void solveQueens(int board[8][8], int row, vector<vector<int>>& configurations) {
    if (row == 8) {
        // If all queens are placed, add the configuration to the result
        vector<int> config;
        for (int i = 0; i < 8; i++) {
            for (int j = 0; j < 8; j++) {
                if (board[i][j] == 1) {
                    config.push_back(j);
                }
            }
        }
        configurations.push_back(config);
    } else {
        for (int col = 0; col < 8; col++) {
            if (isValidMove(board, row, col)) {
                board[row][col] = 1; // Place a queen at position (row, col)
                solveQueens(board, row + 1, configurations); // Recur for the next row
                board[row][col] = 0; // Backtrack
            }
        }
    }
}

// Function to load initial queen positions from a JSON file
vector<vector<int>> loadInitialPositions(const string& filename) {
    ifstream file(filename);
    Json::Value json;
    file >> json;
    vector<vector<int>> positions;
    for (const auto& position : json["positions"]) {
        vector<int> row;
        for (const auto& val : position["row"]) {
            row.push_back(val.asInt());
        }
        positions.push_back(row);
    }
    return positions;
}

// Function to solve the 8-Queens problem
vector<vector<int>> solve8Queens(const string& filename) {
    int board[8][8] = {0};
    vector<vector<int>> configurations;
    vector<vector<int>> initialPositions = loadInitialPositions(filename);
    for (const auto& position : initialPositions) {
        for (int i = 0; i < 8; i++) {
            board[i][position[i]] = 1;
        }
        solveQueens(board, 0, configurations);
    }
    return configurations;
}

int main() {
    vector<vector<int>> configurations = solve8Queens("initial_positions.json");
    for (const auto& config : configurations) {
        for (int i = 0; i < 8; i++) {
            for (int j = 0; j < 8; j++) {
                cout << (config[i] == j ? "Q " : ". ");
            }
            cout << endl;
        }
        cout << endl;
    }
    return 0;
}
