#include <iostream>
#include <vector>
#include <stdexcept>

class PriorityQueue {
private:
    std::vector<int> heap;

    void heapifyUp(int index) {
        if (index == 0) return;
        int parentIndex = (index - 1) / 2;
        if (heap[parentIndex] > heap[index]) {
            std::swap(heap[parentIndex], heap[index]);
            heapifyUp(parentIndex);
        }
    }

    void heapifyDown(int index) {
        int smallest = index;
        int leftChildIndex = 2 * index + 1;
        int rightChildIndex = 2 * index + 2;

        if (leftChildIndex < heap.size() && heap[leftChildIndex] < heap[smallest])
            smallest = leftChildIndex;

        if (rightChildIndex < heap.size() && heap[rightChildIndex] < heap[smallest])
            smallest = rightChildIndex;

        if (smallest != index) {
            std::swap(heap[index], heap[smallest]);
            heapifyDown(smallest);
        }
    }

public:
    void insert(int value) {
        heap.push_back(value);
        heapifyUp(heap.size() - 1);
    }

    int removeMin() {
        if (heap.empty()) {
            throw std::runtime_error("Priority queue is empty");
        }

        int min = heap[0];
        heap[0] = heap.back();
        heap.pop_back();
        heapifyDown(0);
        return min;
    }

    int getMin() {
        if (heap.empty()) {
            throw std::runtime_error("Priority queue is empty");
        }
        return heap[0];
    }
};

int main() {
    PriorityQueue pq;
    pq.insert(5);
    pq.insert(3);
    pq.insert(8);
    std::cout << pq.getMin() << std::endl;  // Output: 3
    std::cout << pq.removeMin() << std::endl;  // Output: 3
    std::cout << pq.getMin() << std::endl;  // Output: 5
    return 0;
}
