// Structure to represent a point
struct Point {
    double x, y;
};

// Function to calculate the Euclidean distance between two points
double distance(const Point& p1, const Point& p2) {
    return sqrt(pow(p1.x - p2.x, 2) + pow(p1.y - p2.y, 2));
}

// Function to find the nearest coffee shop
Point findNearestCoffeeShop(const std::vector<Point>& coffeeShops, const Point& userLocation) {
    // Sort the coffee shops based on their distance from the user location
    std::vector<Point> sortedCoffeeShops = coffeeShops;
    std::sort(sortedCoffeeShops.begin(), sortedCoffeeShops.end(),
              [&userLocation](const Point& a, const Point& b) {
                  return distance(a, userLocation) < distance(b, userLocation);
              });

    // Return the nearest coffee shop
    return sortedCoffeeShops[0];
}

int main() {
    int numCoffeeShops;
    std::cin >> numCoffeeShops;

    std::vector<Point> coffeeShops(numCoffeeShops);
