using namespace std;

struct City {
    string name;
    int distance;
};

bool compareCities(const City& a, const City& b) {
    return a.distance < b.distance;
}

void printPath(const vector<string>& path) {
    cout << "Path: ";
    for (int i = 0; i < path.size() - 1; ++i) {
        cout << path[i] << " -> ";
    }
    cout << path.back() << endl;
}

void generatePaths(const vector<string>& currentPath, const vector<City>& cities, int startIndex, vector<vector<string>>& allPaths) {
    if (currentPath.size() == cities.size()) {
        allPaths.push_back(currentPath);
        return;
    }

    for (int i = startIndex; i < cities.size(); ++i) {
        if (find(currentPath.begin(), currentPath.end(), cities[i].name) == currentPath.end()) {
            currentPath.push_back(cities[i].name);
            generatePaths(currentPath, cities, i + 1, allPaths);
            currentPath.pop_back();
        }
    }
}

int calculateTotalDistance(const vector<string>& path, const vector<City>& cities) {
    int totalDistance = 0;
    for (int i = 0; i < path.size() - 1; ++i) {
        for (const auto& city : cities) {
            if (city.name == path[i] || city.name == path[i + 1]) {
                totalDistance += city.distance;
                break;
            }
        }
    }
    return totalDistance;
}

int main() {
    vector<City> cities = {
        {"City A", 10},
        {"City B", 15},
        {"City C", 20},
        {"City D", 25},
        {"City E", 30}
    };

    vector<string> path;
    vector<vector<string>> allPaths;
    generatePaths(path, cities, 0, allPaths);

    int minDistance = numeric_limits<int>::max();
    int optimalPathIndex = -1;
    for (int i = 0; i < allPaths.size(); ++i) {
        int distance = calculateTotalDistance(allPaths[i], cities);
        if (distance < minDistance) {
            minDistance = distance;
            optimalPathIndex = i;
        }
    }

    printPath(allPaths[optimalPathIndex]);
    cout << "Minimum Distance: " << minDistance << endl;

    return 0;
}
